\begin{algorithm}[H]
 \caption{Weighted split-CQR} \label{algo:split-CQR}
 \textbf{Input: } level $\alpha$, data $\mathcal{Z} = (X_{i}, Y_{i})_{i\in \mathcal{I}}$, testing point $x$, function $\hat{q}_{\beta}(x; \mathcal{D})$ to fit $\beta$-th conditional

 \hspace{1.4cm} quantile and function $\hat{w}(x; \mathcal{D})$ to fit the weight function at $x$ using $\mathcal{D}$ as data

 \textbf{Procedure: }
 \begin{algorithmic}[1]
 \State Split $\mathcal{Z}$ into a training fold $\mathcal{Z}_{\mathrm{tr}} \triangleq (X_{i}, Y_{i})_{i\in \mathcal{I}_{\mathrm{tr}}}$ and a calibration fold $\mathcal{Z}_{\mathrm{ca}}\triangleq (X_{i}, Y_{i})_{i\in \mathcal{I}_{\mathrm{ca}}}$
 \State For each $i \in \mathcal{I}_{\mathrm{ca}}$, compute the score $V_{i} = \max\{\hat{q}_{\alpha_{\mathrm{lo}}}(X_{i}; \mathcal{Z}_{\mathrm{tr}}) - Y_{i}, Y_{i} - \hat{q}_{\alpha_{\mathrm{hi}}}(X_{i}; \mathcal{Z}_{\mathrm{tr}})\}$
 \State For each $i \in \mathcal{I}_{\mathrm{ca}}$, compute the weight $W_{i} = \hat{w}(X_{i}; \mathcal{Z}_{\mathrm{tr}}) \in [0, \infty)$
 \State Compute the normalized weights $\hat{p}_{i}(x) = \frac{W_{i}}{\sum_{i\in \mathcal{I}_{\mathrm{ca}}}W_{i} + \hat{w}(x; \mathcal{Z}_{\mathrm{tr}})}$ and $\hat{p}_{\infty}(x) = \frac{\hat{w}(x; \mathcal{Z}_{\mathrm{tr}})}{\sum_{i\in \mathcal{I}_{\mathrm{ca}}}W_{i} + \hat{w}(x; \mathcal{Z}_{\mathrm{tr}})}$
 \State Compute $\eta(x)$ as the $(1 - \alpha)$-th quantile of the distribution $\sum_{i\in \mathcal{I}_{\mathrm{ca}}}\hat{p}_{i}(x)\delta_{V_{i}} + \hat{p}_{\infty}(x)\delta_{\infty}$
 \end{algorithmic}

 \textbf{Output: $\hat{C}(x) = [\hat{q}_{\alpha_{\mathrm{lo}}}(x; \mathcal{Z}_{\mathrm{tr}}) - \eta(x), \hat{q}_{\alpha_{\mathrm{hi}}}(x; \mathcal{Z}_{\mathrm{tr}}) + \eta(x)]$}
\end{algorithm}

