\begin{theorem}\label{thm:double_robustness_ATE}
 Let $N = |\mathcal{Z}_{\mathrm{tr}}|$ and $n = |\mathcal{Z}_{\mathrm{ca}}|$. Further, let
 $\hat{q}_{\beta, N}(x) = \hat{q}_{\beta, N}(x; \mathcal{Z}_{\mathrm{tr}})$ be an
 estimate of the $\beta$-th conditional quantile $q_{\beta}(x)$ of
 $Y(1)$ given $X = x$, $\hat{e}_{N}(x) = \hat{e}_{N}(x; \mathcal{Z}_{\mathrm{tr}})$ be
 an estimate of $e(x)$, and $\hat{C}_{N, n}(x)$ be the resulting
 interval from Algorithm \ref{algo:split-CQR}. Assume that
 $\mathbb{E}[1 / \hat{e}_{N}(X)\mid \mathcal{Z}_{\mathrm{tr}}] < \infty$ and
 $\mathbb{E}[1 / e(X)] < \infty$. Assume that one of the following holds:
 \begin{enumerate}[\textbf{A}1]
 \item $\displaystyle \lim_{N\rightarrow \infty}\mathbb{E}\bigg|\frac{1}{\hat{e}_{N}(X)} - \frac{1}{e(X)}\bigg| = 0$;
 \item
 \begin{enumerate}[(1)]
 \item $\alpha_{\mathrm{hi}} - \alpha_{\mathrm{lo}} = 1 - \alpha$,
 \item there exists $r, b_{1}, b_{2} > 0$ such that
 $\mathbb{P}(Y(1) = y \mid X = x) \in [b_{1}, b_{2}]$ uniformly over all
 $(x, y)$ with
 $y\in [q_{\alpha_{\mathrm{lo}}}(x) - r, q_{\alpha_{\mathrm{lo}}}(x) + r]\cup
 [q_{\alpha_{\mathrm{hi}}}(x) - r, q_{\alpha_{\mathrm{hi}}}(x) + r]$,
 \item there exists $\delta > 0$ such that
 \[\limsup_{N\rightarrow \infty}\mathbb{E}\left[\frac{1}{\hat{e}_{N}(X)^{1 + \delta}}\right] < \infty, \quad \lim_{N\rightarrow \infty}\mathbb{E}\left[\frac{H_{N}(X)}{\hat{e}_{N}(X)}\right] = \lim_{N\rightarrow \infty}\mathbb{E}\left[\frac{H_{N}(X)}{e(X)}\right] = 0,\]
 where
 \[\displaystyle H_{N}(x) = \max\{|\hat{q}_{\alpha_{\mathrm{lo}}, N}(x) - q_{\alpha_{\mathrm{lo}}}(x)|, |\hat{q}_{\alpha_{\mathrm{hi}}, N}(x) - q_{\alpha_{\mathrm{hi}}}(x)|\}.\]
 \end{enumerate}
 \end{enumerate}
 Then under SUTVA and the strong ignorability assumption,
 \begin{equation}
 \label{eq:unconditional_coverage}
 \lim_{N, n\rightarrow\infty}\mathbb{P}_{(X, Y(1))\sim P_{X}\times P_{Y(1)\mid X}}(Y(1) \in \hat{C}_{N, n}(X))\ge 1 - \alpha.
 \end{equation}
 Furthermore, if \textbf{A}2 holds, then for any $\epsilon > 0$,
 \begin{equation}
 \label{eq:conditional_coverage}
 \lim_{N, n\rightarrow\infty}\mathbb{P}_{X\sim P_{X}}\left( \mathbb{P}(Y(1)\in \hat{C}_{N, n}(X)\mid X)\le 1 - \alpha - \epsilon\right) = 0.
 \end{equation}
\end{theorem}

