\begin{algorithm}[H]
 \caption{(Unweighted) conformal inference for interval outcomes} \label{algo:int}
 \textbf{Input: } level $\gamma$, data $\mathcal{Z} = (X_{i}, C_{i})_{i\in \mathcal{I}}$ where $C_{i} = [C_{i}^{L}, C_{i}^{R}]$, testing point $x$,

 \hspace{1.3cm} functions $\hat{m}^{L}(x; \mathcal{D}), \hat{m}^{R}(x; \mathcal{D})$ to fit the conditional mean/median of $C^{L}, C^{R}$

 \textbf{Procedure: }
 \begin{algorithmic}[1]
 \State Split $\mathcal{Z}$ into a training fold $\mathcal{Z}_{\mathrm{tr}} \triangleq (X_{i}, C_{i})_{i\in \mathcal{I}_{\mathrm{tr}}}$ and a calibration fold $\mathcal{Z}_{\mathrm{ca}}\triangleq (X_{i}, C_{i})_{i\in \mathcal{I}_{\mathrm{ca}}}$
 \State For each $i \in \mathcal{I}_{\mathrm{ca}}$, compute score $V_{i} = \max\{\hat{m}^{L}(X_{i}; \mathcal{Z}_{\mathrm{tr}}) - C_{i}^{L}, C_{i}^{R} - \hat{m}^{R}(X_{i}; \mathcal{Z}_{\mathrm{tr}})\}$
 \State Compute $\eta$ as the $(1 - \gamma)(1 + 1 / |\mathcal{Z}_{\mathrm{ca}}|)$ quantile of the empirical distribution of $\{V_{i}: i\in \mathcal{I}_{\mathrm{ca}}\}$
 \end{algorithmic}

 \textbf{Output: $\hat{\mathcal{C}}(x) = [\hat{m}^{L}(x; \mathcal{Z}_{\mathrm{tr}}) - \eta, \hat{m}^{R}(x; \mathcal{Z}_{\mathrm{tr}}) + \eta]$}
\end{algorithm}

\begin{theorem}\label{thm:int_conformal}
 Consider Algorithm \ref{algo:int} and assume $(X_{i}, C_{i})\stackrel{i.i.d.}{\sim} (X, C)$. Then
 \[\mathbb{P}(C\subset \hat{\mathcal{C}}(X))\ge 1 - \gamma.\]
\end{theorem}

\begin{algorithm}
 \caption{Nested approach for interval estimates of ITE} \label{algo:two_step}
 \textbf{Input: } level $\alpha$, level $\gamma$ (only for exact version), data $\mathcal{Z} = (X_{i}, Y_{i}, T_{i})_{i=1}^{n}$, testing point $x$

 \vspace{0.2cm}
 \textbf{Step I: data splitting}
 \begin{algorithmic}[1]
 \State Split the data into two folds $\mathcal{Z}_{1}$ and $\mathcal{Z}_{2}$
 \State Estimate propensity score $\hat{e}(x)$ on $\mathcal{Z}_{1}$
 \end{algorithmic}

 \vspace{0.2cm}
 \textbf{Step II: counterfactual inference on $\mathcal{Z}_{2}$}
 \begin{algorithmic}[1]
 \For{$i$ in $\mathcal{Z}_{2}$ with $T_{i} = 1$}
 \State Compute $[\hat{Y}_{i}^{L}(0), \hat{Y}_{i}^{R}(0)]$ in Algorithm \ref{algo:split-CQR} on $\mathcal{Z}_{1}$ with level $\alpha$ and $w_{0}(x) = \hat{e}(x) / (1 - \hat{e}(x))$
 \State Compute $\hat{C}_{i} = [Y_{i}(1) - \hat{Y}_{i}^{R}(0), Y_{i}(1) - \hat{Y}_{i}^{L}(0)]$
 \EndFor
 \For{$i$ in $\mathcal{Z}_{2}$ with $T_{i} = 0$}
 \State Compute $[\hat{Y}_{i}^{L}(1), \hat{Y}_{i}^{R}(1)]$ in Algorithm \ref{algo:split-CQR} on $\mathcal{Z}_{1}$ with level $\alpha$ and $w_{1}(x) = (1 - \hat{e}(x)) / \hat{e}(x)$
 \State Compute $\hat{C}_{i} = [\hat{Y}_{i}^{L}(1) - Y_{i}(0), \hat{Y}_{i}^{R}(1) - Y_{i}(0)]$
 \EndFor
 \end{algorithmic}

 \vspace{0.2cm}
 \textbf{Step III: Interval of ITE on the testing point}
 \begin{algorithmic}[1]
 \State (Exact version) Apply Algorithm \ref{algo:int} on $(X_{i}, \hat{C}_{i})_{i\in \mathcal{Z}_{2}}$ with level $\gamma$, yielding an interval $\hat{\mathcal{C}}_\text{ITE}(x)$

 \State (Inexact version) Fit conditional quantiles of $\hat{C}^{L}$ and $\hat{C}^{R}$, yielding an interval $\hat{\mathcal{C}}_\text{ITE}(x)$
 \end{algorithmic}
 \textbf{Output: $\hat{\mathcal{C}}_\text{ITE}(x)$}\label{algo:nest_CQR}
\end{algorithm}

