\begin{theorem}\label{thm:double_robustness_q}
 In the setting of Theorem \ref{thm:double_robustness_w}, assume further that
 \begin{enumerate}[(1)]
 \item $\alpha_{\mathrm{hi}} - \alpha_{\mathrm{lo}} = 1 - \alpha$;
 \item there exist $r, b_{1}, b_{2} > 0$ such that $\mathbb{P}(Y = y \mid X = x) \in [b_{1}, b_{2}]$ uniformly over all $(x, y)$ with $y\in [q_{\alpha_{\mathrm{lo}}}(x) - r, q_{\alpha_{\mathrm{lo}}}(x) + r]\cup [q_{\alpha_{\mathrm{hi}}}(x) - r, q_{\alpha_{\mathrm{hi}}}(x) + r]$;
 \item $\mathbb{P}_{X\sim Q_{X}}(w(X) < \infty) = 1$, and there exist $\delta, M > 0$ such that $\left(\mathbb{E}\left[\hat{w}_{N}(X)^{1 + \delta}\right]\right)^{1 / (1 + \delta)} \le M$;
 \item there exist $k, \ell > 0$ such that $\displaystyle \lim_{N\rightarrow \infty} \mathbb{E}[\hat{w}_{N}(X)H_{N}^{k}(X)] = \lim_{N\rightarrow \infty} \mathbb{E}[w(X)H_{N}^{\ell}(X)] = 0$, where
 \[\displaystyle H_{N}(x) = \max\{|\hat{q}_{\alpha_{\mathrm{lo}}, N}(x) - q_{\alpha_{\mathrm{lo}}}(x)|, |\hat{q}_{\alpha_{\mathrm{hi}}, N}(x) - q_{\alpha_{\mathrm{hi}}}(x)|\}.\]
 \end{enumerate}
 Then there is a constant $B_{1}$ that only depends on $r, b_1, b_2, \delta, M, k, \ell$ such that
 \begin{multline}
 \mathbb{P}_{(X, Y)\sim Q_{X}\times P_{Y\mid X}}(Y \in \hat{C}_{N, n}(X))\ge 1 - \alpha \\
 -B_{1} \left\{\frac{(\log n)^{(1 + \delta') / 2(2 + \delta')}}{n^{\delta' / (2 + \delta')}} + \left(\mathbb{E}[\hat{w}_{N}(X)H_{N}^{k}(X)]\right)^{1 / (2+k)} + \left(\mathbb{E}[w(X)H_{N}^{\ell}(X)]\right)^{1/ (1+\ell)}\right\},\label{eq:unconditional_coverage_rate_q}
 \end{multline}
 where $\delta' = \min\{\delta, 1\}$. Furthermore, for any $\beta\in (0, 1)$, there is a constant $B_{2}$ that only depends on $r, b_1, b_2, \delta, M, k, \ell, \beta$ such that, with probability at least $1 - \beta$,
 \begin{multline}
 \mathbb{P}_{(X, Y)\sim Q_{X}\times P_{Y\mid X}}(Y \in \hat{C}_{N, n}(X) \mid X )\ge 1 - \alpha \\
 - B_{2}\left\{\frac{(\log n)^{(1 + \delta') / 2(2 + \delta')}}{n^{\delta' / (2 + \delta')}} + \left(\mathbb{E}[\hat{w}_{N}(X)H_{N}^{k}(X)]\right)^{1 / (2+k)} + \left(\mathbb{E}[w(X)H_{N}^{\ell}(X)]\right)^{1/ \ell}\right\}.\label{eq:conditional_coverage_rate_q}
 \end{multline}
 \end{theorem}

\begin{lemma}[Equation (2) in Lemma 1 from \cite{barber2019conformal}]\label{lem:delta_infty}
 Let $v_{1}, \ldots, v_{n+1} \in \mathbb{R}$ and $(p_{1}, \ldots,
 p_{n+1}) \in \mathbb{R}$ be non-negative reals summing to
 $1$. Then for any $\beta \in [0, 1]$ and
 \begin{multline*}
 v_{n+1}\le \mathrm{Quantile}\left(\beta; \sum_{i=1}^{n+1}p_{i}\delta_{v_{i}}\right)
 \quad \Longleftrightarrow \quad v_{n+1}\le \mathrm{Quantile}\left( \beta; \sum_{i=1}^{n}p_{i}\delta_{v_{i}} + p_{n+1}\delta_{\infty}\right).
 \end{multline*}
\end{lemma}

\begin{lemma}[Equation (10) from \cite{berrett2019conditional}]\label{lem:tv}
 Let $d_{\mathrm{TV}}(Q_{1X}, Q_{2X})$ denote the total-variation distance between $Q_{1X}$ and $Q_{2X}$. Then
 \[d_{\mathrm{TV}}(Q_{1X}\times P_{Y\mid X}, Q_{2X}\times P_{Y\mid X}) = d_{\mathrm{TV}}(Q_{1X}, Q_{2X}).\]
\end{lemma}

